  const typeNames = {"1":"Der Reformer","2":"Der Helfer","3":"Der Dynamiker","4":"Der Individualist","5":"Der Beobachter","6":"Der Loyale","7":"Der Enthusiast","8":"Der Herausforderer","9":"Der Friedensstifter"};

